css:
.print-heading {
  text-align: center;
  margin-bottom: 30px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
}

.print-heading p {
  margin: 6px 0 0;
}

.section-heading {
  margin-top: 22px;
  margin-bottom: 10px;
  padding-bottom: 5px;
  border-bottom: 1px solid #b40000;
  font-size: 12pt;
  font-weight: 600;
}

.war-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}

.war-table th,
.war-table td {
  padding: 8px;
  vertical-align: top;
}

.war-table th {
  background-color: #f5f5f5;
  border-bottom: 1px solid #ddd;
  font-weight: 600;
  text-align: left;
}

.war-table td {
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

.war-table td:last-child,
.war-table th:last-child {
  border-right: none;
}

.war-table tbody tr:last-child td {
  border-bottom: none;
}

.war-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}

.war-table .number-column {
  width: 38px;
  text-align: center;
}

.war-table .date-column {
  width: 110px;
  white-space: nowrap;
}

.empty-row {
  color: #777;
  font-style: italic;
}

/* Keep headings and their first content block together where possible. */
.section-heading {
  page-break-after: avoid;
}

.war-table tr {
  page-break-inside: avoid;
}

/* Signature block */
.signatures {
  margin-top: 28px;
  page-break-inside: auto;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.signatures tr {
  page-break-inside: avoid;
}

.signatures td {
  border: none;
  vertical-align: bottom;
}

/*
 * Deliberate writing space above each line.
 * This replaces the former empty &nbsp; paragraphs.
 */
.signatures .signature-cell {
  width: 68%;
  padding: 38px 30px 16px 0;
}

.signatures .date-cell {
  width: 32%;
  padding: 38px 0 16px 20px;
}

.signatures .signature-line {
  min-height: 22px;
  border-bottom: 1px solid #222;
}

.signatures .signature-label {
  margin-top: 5px;
  font-size: 10.5pt;
  line-height: 1.3;
}

.signatures .qualifier {
  font-size: 9pt;
  font-style: italic;
}

.signature-introduction {
  margin-top: 22px;
}

.signature-introduction p {
  margin: 0 0 10px;
}

@page {
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
